// NavigationView legado — evite em código novo:
NavigationView {
    ContentView()
        .navigationTitle("Início")
}

// NavigationStack moderno (iOS 16+):
NavigationStack {
    ContentView()
        .navigationTitle("Início")
}

// Forma 1 — link com destino inline:
NavigationStack {
    List(tarefas) { tarefa in
        NavigationLink(tarefa.titulo) {
            DetalheTarefa(tarefa: tarefa)  // criado mesmo sem navegar
        }
    }
}

// Forma 2 — link com valor (preferida para listas):
NavigationStack {
    List(tarefas) { tarefa in
        NavigationLink(tarefa.titulo, value: tarefa)  // só passa o dado
    }
    .navigationDestination(for: Tarefa.self) { tarefa in
        DetalheTarefa(tarefa: tarefa)  // criado quando o usuário navega
    }
}

// NavigationLink com label customizado:
NavigationLink(value: tarefa) {
    TarefaRow(tarefa: tarefa)  // qualquer View como label
}

// Enum que representa os destinos possíveis:
enum Rota: Hashable {
    case detalhe(Tarefa)
    case edicao(Tarefa)
    case configuracoes
}

// App raiz com path controlado:
struct AppView: View {
    @State private var caminho = NavigationPath()

    var body: some View {
        NavigationStack(path: $caminho) {
            ListaDeTarefas(caminho: $caminho)
                .navigationDestination(for: Rota.self) { rota in
                    switch rota {
                    case .detalhe(let tarefa): DetalheTarefa(tarefa: tarefa)
                    case .edicao(let tarefa): EditarTarefa(tarefa: tarefa)
                    case .configuracoes: ConfiguracoesView()
                    }
                }
        }
    }
}

// Navegar de qualquer lugar:
caminho.append(Rota.detalhe(tarefa))  // empurra tela
caminho.removeLast()                  // volta uma tela
caminho.removeLast(2)                 // volta duas telas
caminho = NavigationPath()            // volta para a raiz

struct ListaDeTarefas: View {
    @State private var caminho = NavigationPath()

    var body: some View {
        NavigationStack(path: $caminho) {
            List { ... }
                .navigationTitle("Tarefas")
                .navigationBarTitleDisplayMode(.large)
                .toolbar {
                    ToolbarItem(placement: .topBarTrailing) {
                        Button {
                            caminho.append(Rota.novaTarefa)
                        } label: {
                            Image(systemName: "plus")
                        }
                    }
                    ToolbarItem(placement: .topBarLeading) {
                        EditButton()  // ativa edit mode da List
                    }
                }
        }
    }
}

// Sheet com booleano — simples mas sem dados:
struct ListaView: View {
    @State private var mostrarFormulario = false

    var body: some View {
        Button("Nova Tarefa") { mostrarFormulario = true }
            .sheet(isPresented: $mostrarFormulario) {
                FormularioNovaTarefa()
            }
    }
}

// Sheet com item opcional — preferido quando passa dados:
struct ListaView: View {
    @State private var tarefaParaEditar: Tarefa?

    var body: some View {
        List(tarefas) { tarefa in
            Button(tarefa.titulo) { tarefaParaEditar = tarefa }
        }
        .sheet(item: $tarefaParaEditar) { tarefa in
            EditarTarefaView(tarefa: tarefa)  // tarefa passada diretamente
        }
    }
}

// Fechando o sheet de dentro:
struct EditarTarefaView: View {
    @Environment(\.dismiss) private var fechar

    var body: some View {
        Button("Fechar") { fechar() }
    }
}

struct AppView: View {
    @State private var mostrarOnboarding = !UsuarioPreferencias.onboardingVisto

    var body: some View {
        ContentView()
            .fullScreenCover(isPresented: $mostrarOnboarding) {
                OnboardingView()
            }
    }
}

// Fechando fullScreenCover (obrigatório — usuário não pode arrastar):
struct OnboardingView: View {
    @Environment(\.dismiss) private var fechar

    var body: some View {
        VStack {
            Text("Bem-vindo!")
            Button("Começar") {
                UsuarioPreferencias.onboardingVisto = true
                fechar()
            }
        }
    }
}

// Alert de confirmação:
struct DetalheView: View {
    @State private var mostrarConfirmacaoDeletar = false
    let tarefa: Tarefa

    var body: some View {
        Button("Deletar", role: .destructive) {
            mostrarConfirmacaoDeletar = true
        }
        .alert("Deletar tarefa?", isPresented: $mostrarConfirmacaoDeletar) {
            Button("Deletar", role: .destructive) { deletar(tarefa) }
            Button("Cancelar", role: .cancel) { }  // role: .cancel fecha o alert
        } message: {
            Text("Essa ação não pode ser desfeita.")
        }
    }
}

// confirmationDialog — para múltiplas opções:
.confirmationDialog("O que deseja fazer?", isPresented: $mostrarOpcoes) {
    Button("Editar") { editar(tarefa) }
    Button("Compartilhar") { compartilhar(tarefa) }
    Button("Deletar", role: .destructive) { deletar(tarefa) }
    Button("Cancelar", role: .cancel) { }
} message: {
    Text(tarefa.titulo)
}

