struct ExemploAnimacao: View {
    @State private var expandido = false

    var body: some View {
        Rectangle()
            .frame(width: expandido ? 200 : 50, height: 50)
            .onTapGesture {
                withAnimation(.easeInOut(duration: 0.3)) {
                    expandido.toggle()
                }
            }
    }
}
// O Rectangle SEMPRE está na View tree.
// Quando 'expandido' muda, a largura muda — e SwiftUI anima essa mudança.
// O Rectangle é o MESMO nodo na Render tree, só a propriedade muda.

// PROPERTY ANIMATION — mesmo nodo, propriedade muda:
// Você vê uma interpolação suave de 50→200
var body: some View {
    Rectangle()
        .frame(width: expandido ? 200 : 50, height: 50)
        .onTapGesture {
            withAnimation { expandido.toggle() }
        }
}

// TRANSITION (não property animation) — dois nodos distintos:
// Você vê o retângulo menor fazer fade-out e o maior fazer fade-in
var body: some View {
    if expandido {
        Rectangle().frame(width: 200, height: 50)  // nodo 1: elseBranch
    } else {
        Rectangle().frame(width: 50, height: 50)   // nodo 2: ifBranch
    }
    // Quando expandido muda: o SwiftUI REMOVE o nodo antigo e INSERE o novo
    // Não há interpolação de largura — é uma troca de Views!
}

// withAnimation sem parâmetro — usa .default:
Button("Animar") {
    withAnimation {
        expandido.toggle()
    }
}

// withAnimation com timing curve:
Button("Animar") {
    withAnimation(.spring(duration: 0.5, bounce: 0.4)) {
        expandido.toggle()
    }
}

// Timing curves disponíveis:
withAnimation(.linear(duration: 0.3))           // velocidade constante
withAnimation(.easeIn(duration: 0.3))           // começa devagar
withAnimation(.easeOut(duration: 0.3))          // termina devagar
withAnimation(.easeInOut(duration: 0.3))        // começa e termina devagar
withAnimation(.spring())                         // mola — física natural
withAnimation(.spring(duration: 0.5, bounce: 0.3))  // mola com bounce
withAnimation(.bouncy)                           // iOS 17 — preset com bounce

// Animação com completion handler (iOS 17+):
withAnimation(.easeOut(duration: 0.5)) {
    mostrar.toggle()
} completion: {
    print("Animação concluída")  // callback quando a animação termina
}

// Animação implícita — anima quando 'expandido' muda:
Rectangle()
    .frame(width: expandido ? 200 : 50, height: 50)
    .animation(.easeInOut(duration: 0.3), value: expandido)  // CORRETO
    .onTapGesture { expandido.toggle() }  // sem withAnimation!

// A animação acontece qualquer que seja a origem da mudança:
// - Toque do usuário
// - Mudança vinda da rede
// - Timer
// Tudo que mudar 'expandido' vai animar

// DEPRECATED (iOS 15+) — sem 'value', anima TUDO:
Rectangle()
    .animation(.easeInOut)  // ← evite! causa animações inesperadas

// iOS 17 — escopo específico de propriedades:
Text("Olá")
    .opacity(visivel ? 1 : 0)
    .animation(.easeOut) {
        $0.rotationEffect(rotacionado ? .degrees(180) : .zero)  // só rotation anima
    }

struct TransicoesView: View {
    @State private var visivel = true

    var body: some View {
        VStack {
            if visivel {
                Text("Apareço e sumo")
                    .padding()
                    .background(.blue)
                    // Transições built-in:
                    .transition(.slide)            // desliza da esquerda
                    // .transition(.scale)         // cresce/encolhe do centro
                    // .transition(.opacity)       // fade (padrão)
                    // .transition(.move(edge: .bottom))  // entra/sai de baixo

                    // Combinando transições:
                    // .transition(.scale.combined(with: .opacity))

                    // Assimétricas — entrada ≠ saída:
                    // .transition(.asymmetric(
                    //     insertion: .slide,
                    //     removal: .move(edge: .top)
                    // ))
            }

            Button(visivel ? "Ocultar" : "Mostrar") {
                withAnimation(.spring(duration: 0.4)) {  // OBRIGATÓRIO para transitions
                    visivel.toggle()
                }
            }
        }
    }
}
